import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';

const statusCores = {
  NOVO: '#1976d2',
  ATIVO: '#388e3c',
  CORRIGIR: '#fbc02d',
  SUSPENSO: '#d32f2f'
};
const statusNomes = {
  NOVO: 'Novo',
  ATIVO: 'Ativo',
  CORRIGIR: 'Corrigir',
  SUSPENSO: 'Suspenso'
};

const DetalheCliente = () => {
  const { id } = useParams();
  const [cliente, setCliente] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`http://localhost:5000/api/clientes/${id}`)
      .then(resp => resp.json())
      .then(data => {
        setCliente(data);
        setLoading(false);
      });
  }, [id]);

  if (loading) return <p>Carregando detalhes...</p>;
  if (!cliente || cliente.error) return <p>Cliente não encontrado.</p>;

  return (
    <div style={{maxWidth:'1100px',margin:'2rem auto'}}>
      <Link to="/" style={{textDecoration:'none',color:'#1976d2'}}>&larr; Voltar</Link>
      <div style={{background:'#1976d2',borderRadius:'0 0 20px 20px',padding:'2rem',color:'#fff',marginTop:'1rem',position:'relative',boxShadow:'0 2px 8px #0001'}}>
        <h2 style={{margin:0,fontWeight:700}}>{cliente.razaoSocial}</h2>
        <div style={{display:'flex',alignItems:'center',gap:'1rem',marginTop:'0.5rem'}}>
          <span style={{fontWeight:700,fontSize:'1.1rem'}}>CNPJ: {cliente.cnpj}</span>
          <span style={{background:statusCores[cliente.status],color:'#fff',borderRadius:'12px',padding:'0.2rem 1rem',fontWeight:600,fontSize:'0.95rem'}}>{statusNomes[cliente.status]}</span>
        </div>
        <div style={{marginTop:'1rem',fontSize:'1.1rem'}}>
          <div><b>E-mail:</b> {cliente.email}</div>
          <div><b>Telefone:</b> {cliente.telefone}</div>
          <div><b>Consultoria:</b> {cliente.consultoria}</div>
        </div>
        <button style={{position:'absolute',top:'2rem',right:'2rem',background:'#1976d2',color:'#fff',border:'2px solid #fff',borderRadius:'6px',padding:'0.5rem 2rem',fontWeight:'bold',fontSize:'1rem',cursor:'pointer',transition:'background 0.2s'}}>
          Editar
        </button>
      </div>
      <div style={{marginTop:'2rem',background:'#fff',borderRadius:'16px',minHeight:'300px',boxShadow:'0 2px 8px #0001',padding:'2rem'}}>
        {/* Conteúdo futuro: abas, cards, etc. */}
      </div>
    </div>
  );
};

export default DetalheCliente;
